import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';

import Header from './components/Header';
import Home from './components/Home';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import GestionOfertas from './components/GestionOfertas';

function App() {
  // Inicialización inmediata para evitar parpadeos de roles
  const [isLoggedIn, setIsLoggedIn] = useState(!!localStorage.getItem('token-falso'));
  const [userRole, setUserRole] = useState(localStorage.getItem('user-role')); 

  const cerrarSesion = () => {
    localStorage.clear();
    setIsLoggedIn(false);
    setUserRole(null);
    // Usamos Navigate o redirigimos manualmente para limpiar el estado
    window.location.href = '/'; 
  };

  return (
    <Router>
      <Header isLoggedIn={isLoggedIn} userRole={userRole} cerrarSesion={cerrarSesion} />
      <main style={{ minHeight: 'calc(100vh - 75px)' }}>
        <Routes>
          <Route path="/" element={<Home />} />

          {/* Si ya está logueado, el Login redirige al Home o Dashboard automáticamente */}
          <Route path="/login" element={
            isLoggedIn ? (userRole === 'vendedor' ? <Navigate to="/dashboard" /> : <Navigate to="/" />) 
                       : <Login setIsLoggedIn={setIsLoggedIn} setUserRole={setUserRole} />
          } />

          {/* Solo el vendedor entra aquí */}
          <Route path="/dashboard" element={
            isLoggedIn && userRole === 'vendedor' ? <Dashboard /> : <Navigate to="/login" />
          } />

          <Route path="/ofertas/:id" element={
            isLoggedIn && userRole === 'vendedor' ? <GestionOfertas /> : <Navigate to="/login" />
          } />

          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
      </main>
    </Router>
  );
}

export default App;
